sql:
SELECT median_charge
FROM procedure_data
WHERE year = 2020 AND number_of_cases > 50;

SELECT SUM(total_charges) AS total_charges_for_year
FROM procedure_data
WHERE procedure_id = 1 AND year = 2020;

SELECT median_charge
FROM procedure_data
WHERE data_id = 1;

SELECT COUNT(provider_id) AS number_of_providers_offering_procedure
FROM provider_procedures
WHERE procedure_id = 1;

SELECT procedure_id, COUNT(*) AS number_of_procedures
FROM procedure_data
GROUP BY procedure_id;

SELECT state_id, year, number_of_cases, median_charge, AVG(median_charge) OVER () AS average_median_charge
FROM procedure_data
WHERE state_id = 1 AND year = 2020;

SELECT SUM(total_charges) AS total_charges_sum
FROM procedure_data
WHERE state_id = 1;
